92	function createMockInstrumentarium(tools: ToolDefinition[]): InstrumentariumApi {
93	  const resolved: ResolvedTool[] = tools.map((def) => ({ definition: def, pluginId: 'test' }));
94	  return {
95	    list: () => resolved,
96	    find: (name: string) => resolved.find((t) => t.definition.name === name) ?? null,
97	    resolve: () => resolved,
98	  };
99	}
