describe('permissionToMethod', () => {
  it("undefined → 'GET'", () => {
    assert.equal(permissionToMethod(undefined), 'GET');
  });

  it("'read' → 'GET'", () => {
    assert.equal(permissionToMethod('read'), 'GET');
  });

