        params: { message: z.string().optional() },
        handler: async () => ({ ok: true }),
      }),
      tool({
        name: 'anima-only-tool',
        description: 'Anima only',
        callableBy: ['anima'],
        params: {},
        handler: async () => ({}),
      }),
    ];

